import base64
import io
import zipfile

ARCHIVE_CONSTANT =""
raw_bytes = base64.b64decode(ARCHIVE_CONSTANT)

# 2. Оборачиваем байты в виртуальный файл
virtual_file = io.BytesIO(raw_bytes)

# 3. Работаем с архивом прямо из памяти!
with zipfile.ZipFile(virtual_file, 'r') as zip_ref:
    print("Файлы внутри нашего зашитого архива:", zip_ref.namelist())

    # Можно распаковать их на диск
    zip_ref.extractall('unpacked_from_memory')